features.snippet:
reg data_d, data_q;
always @(*) begin
  data_d = data_q;
  case (sel)
    2'b10: data_d = 1'b0;
    2'b01: data_d = 1'b1;
    default:;
  endcase
end

always @(posedge clk) data_q <= data_d;
always @(*) begin
  data_d = data_q;
  case (sel)
    2'b10: data_d = 1'b0;
    2'b01: data_d = 1'b1;
    default:;
  endcase
end
